import{_ as i,o as s,c as a,ao as t}from"./chunks/framework.BwTKejc4.js";const k=JSON.parse('{"title":"Testing likelihoods","description":"","frontmatter":{},"headers":[],"relativePath":"diagnostics-and-validation/testing-likelihoods.md","filePath":"diagnostics-and-validation/testing-likelihoods.md","lastUpdated":null}'),n={name:"diagnostics-and-validation/testing-likelihoods.md"};function r(h,e,l,o,d,c){return s(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="Testing-likelihoods" tabindex="-1">Testing likelihoods <a class="header-anchor" href="#Testing-likelihoods" aria-label="Permalink to &quot;Testing likelihoods {#Testing-likelihoods}&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Status — Implemented</p><p>Mirrors drmTMB&#39;s <a href="https://itchyshin.github.io/drmTMB/articles/testing-likelihoods.html" target="_blank" rel="noreferrer">Testing likelihoods</a>. This page describes how DRM.jl validates each likelihood today — the gates that actually run in <code>test/runtests.jl</code> and in the engine-quality battery (Workflow Q).</p></div><p>Every family and every random-effect path in DRM.jl is checked the same way: <strong>write the likelihood, then prove it numerically</strong> before it is wired into the public API. There are four standing gates.</p><h2 id="1.-Parameter-recovery-—-the-primary-gate" tabindex="-1">1. Parameter recovery — the primary gate <a class="header-anchor" href="#1.-Parameter-recovery-—-the-primary-gate" aria-label="Permalink to &quot;1. Parameter recovery — the primary gate {#1.-Parameter-recovery-—-the-primary-gate}&quot;">​</a></h2><p>Each family has a <code>test/test_&lt;family&gt;.jl</code> that <strong>simulates from known coefficients, fits, and asserts recovery</strong> within tolerance. This is the Definition-of-Done gate: it confirms the log-likelihood, the link functions, and the <code>sigma ↔ φ</code> mapping are all correct end to end. For example, the Gamma family checks that the log-mean coefficients come back and that the shape recovers through <code>α = 1/σ²</code>:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fit </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> drm</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x, sigma </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Gamma</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(); data </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> data)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">@test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> coef</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fit, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:mu</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">≈</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> β_slope atol </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.06</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">α̂ </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> exp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> coef</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fit, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:sigma</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">])      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># α = 1/σ²</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">@test</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> α̂ </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">≈</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> α_true atol </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2.0</span></span></code></pre></div><p>Recovery tests exist for the full surface: the Gaussian location–scale and bivariate <code>ρ12</code> models, every non-Gaussian family, and each random-effect path (<code>(1|g)</code>, <code>(1+x|g)</code>, crossed <code>(1|g)+(1|h)</code>, the <code>sigma</code>-RE GHQ marginal, and the structured markers).</p><h2 id="2.-Exact-gradient-vs-finite-differences" tabindex="-1">2. Exact-gradient vs finite differences <a class="header-anchor" href="#2.-Exact-gradient-vs-finite-differences" aria-label="Permalink to &quot;2. Exact-gradient vs finite differences {#2.-Exact-gradient-vs-finite-differences}&quot;">​</a></h2><p>The verified engine&#39;s selling point is an <strong>exact O(p) gradient</strong> (implicit-function / Takahashi selected inverse). It is held to a finite-difference check: the analytic gradient must match a central finite difference to <strong>≤ 1e-6</strong>. The same FD check guards the crossed sparse-Laplace family gradients (the nuisance derivatives for NB2 / Gamma / Beta). A likelihood whose gradient fails FD does not ship.</p><h2 id="3.-Collapse-/-consistency-cross-checks" tabindex="-1">3. Collapse / consistency cross-checks <a class="header-anchor" href="#3.-Collapse-/-consistency-cross-checks" aria-label="Permalink to &quot;3. Collapse / consistency cross-checks {#3.-Collapse-/-consistency-cross-checks}&quot;">​</a></h2><p>Where a general path should reduce to a simpler, independently-trusted one, the tests assert it does:</p><ul><li><p>a <strong>crossed</strong> random-effect fit must match the <strong>single-factor GHQ</strong> path when one grouping factor collapses to a single level;</p></li><li><p><strong>profile</strong> confidence intervals must agree with <strong>Wald</strong> intervals on the well-identified mean coefficients (<code>confint(; method = :profile)</code> ≈ <code>confint(; method = :wald)</code> on μ), while still bracketing the point estimate;</p></li><li><p>in-sample <code>predict</code> must equal <code>fitted</code>.</p></li></ul><p>These catch sign errors and mis-wired blocks that a single recovery test can miss.</p><h2 id="4.-AD-safety-and-the-information-matrix" tabindex="-1">4. AD-safety and the information matrix <a class="header-anchor" href="#4.-AD-safety-and-the-information-matrix" aria-label="Permalink to &quot;4. AD-safety and the information matrix {#4.-AD-safety-and-the-information-matrix}&quot;">​</a></h2><p>Because the objective is written to be ForwardDiff-safe (<code>zero(eltype(θ))</code>, stable log-densities, clamped predictors), the <strong>Hessian</strong> gives the observed-information <code>vcov</code>, and the stored objective lets <code>confint(; method = :profile)</code> re-optimise the nuisance parameters by inverting the likelihood ratio. The boundary-aware Wald path maps a non-positive / non-finite stored variance to <code>Inf</code> (an unbounded CI for an unidentified direction) rather than a silent <code>NaN</code>.</p><h2 id="Where-the-results-live" tabindex="-1">Where the results live <a class="header-anchor" href="#Where-the-results-live" aria-label="Permalink to &quot;Where the results live {#Where-the-results-live}&quot;">​</a></h2><p>Every gate run is recorded in the <a href="https://github.com/itchyshin/DRM.jl/blob/main/docs/dev-log/check-log.md" target="_blank" rel="noreferrer">check-log</a> — one row per slice, citing the verification command and the result — and the engine-quality battery (FD-gradient ≤ 1e-6, zero-allocation inner loop, multi-shape scaling sweep) is the standing Workflow Q gate run before each tag. The bar is <strong>verify before claiming</strong>: every speed or accuracy number in this repository was reproduced by an independent run.</p>`,17)])])}const g=i(n,[["render",r]]);export{k as __pageData,g as default};
